class TemplateItem {
  final String category;
  final String intro;
  final String readMore;

  const TemplateItem({
    required this.category,
    required this.intro,
    required this.readMore,
  });

  Map<String, dynamic> toJson() => {
        'category': category,
        'intro': intro,
        'readMore': readMore,
      };

  factory TemplateItem.fromJson(Map<String, dynamic> json) => TemplateItem(
        category: json['category'] as String? ?? 'Custom',
        intro: json['intro'] as String? ?? '',
        readMore: json['readMore'] as String? ?? '',
      );

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is TemplateItem &&
          runtimeType == other.runtimeType &&
          category == other.category &&
          intro == other.intro &&
          readMore == other.readMore;

  @override
  int get hashCode => category.hashCode ^ intro.hashCode ^ readMore.hashCode;
}

