  static List<TemplateItem> getTemplatesForLanguage(String langCode) {
    final Map<String, List<TemplateItem>> map = localizedTemplates[langCode] ?? localizedTemplates['en']!;
    final List<TemplateItem> list = [];
    map.forEach((_, items) => list.addAll(items));
    return list;
  }
